"use client"

import { useState, useEffect } from "react"
import { createPortal } from "react-dom"
import { cn } from "../lib/utils"
import { X } from "lucide-react"
import { MenuIcon } from "./menu-icon"

const navItems = [
  { label: "About", href: "#about" },
  { label: "Experience", href: "#experience" },
  { label: "Projects", href: "#projects" },
  { label: "Skills", href: "#skills" },
]

export function Navigation() {
  const [mounted, setMounted] = useState(false)
  const [isScrolled, setIsScrolled] = useState(false)
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false)

  useEffect(() => {
    setMounted(true)
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 10)
    }

    window.addEventListener("scroll", handleScroll)
    return () => window.removeEventListener("scroll", handleScroll)
  }, [])

  return (
    <header
      className={cn(
        "fixed top-0 left-0 right-0 z-50 transition-all duration-300",
        isScrolled ? "bg-black/80 backdrop-blur-md border-b border-frost" : "bg-transparent border-b border-transparent",
      )}
    >
      <nav className="mx-auto max-w-[1200px] px-6 py-4">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-6 z-50 relative">
            <a
              href="#"
              className="font-display-sans text-[#f0f0f0] text-xl font-medium tracking-tight"
              onClick={() => setIsMobileMenuOpen(false)}
            >
              Yinka Salaam
            </a>
          </div>

          {/* Desktop Nav */}
          <ul className="hidden md:flex items-center gap-8">
            {navItems.map((item) => (
              <li key={item.href}>
                <a
                  href={item.href}
                  className="font-display-sans text-[14px] font-medium tracking-[0.35px] text-[#f0f0f0]/80 hover:text-[#f0f0f0] transition-colors"
                  style={{ fontFeatureSettings: '"ss01" on, "ss03" on, "ss04" on' }}
                >
                  {item.label}
                </a>
              </li>
            ))}
          </ul>

          <div className="hidden md:flex items-center gap-4">
            <a
              href="/resume.pdf"
              className="inline-flex items-center justify-center px-4 py-1.5 text-[14px] font-sans font-medium text-[#f0f0f0] bg-transparent rounded-full border border-frost hover-glass transition-colors"
            >
              Resume
            </a>
            <a
              href="#contact"
              className="inline-flex items-center justify-center px-4 py-1.5 text-[14px] font-sans font-medium text-[#000000] bg-[#ffffff] rounded-full transition-opacity hover:opacity-90"
            >
              Contact
            </a>
          </div>

          {/* Mobile Controls */}
          <div className="flex md:hidden items-center gap-4 z-50 relative">
            <button
              className="text-[#f0f0f0] hover:opacity-80 transition-opacity p-1"
              onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
              aria-label={isMobileMenuOpen ? "Close menu" : "Open menu"}
              aria-expanded={isMobileMenuOpen}
            >
              {isMobileMenuOpen ? <X className="w-6 h-6" /> : <MenuIcon className="w-6 h-6" />}
            </button>
          </div>
        </div>
      </nav>

      {/* Full Screen Mobile Menu */}
      {mounted && createPortal(
        <div
          className={cn(
            "fixed inset-0 bg-[#000000]/95 backdrop-blur-xl z-40 md:hidden transition-all duration-500 flex flex-col justify-center items-center",
            isMobileMenuOpen ? "opacity-100 pointer-events-auto" : "opacity-0 pointer-events-none"
          )}
        >
          <ul className="flex flex-col items-center gap-8 w-full px-6">
            {navItems.map((item, index) => (
              <li
                key={item.href}
                className={cn(
                  "w-full text-center transform transition-all duration-500 delay-[100ms]",
                  isMobileMenuOpen ? "translate-y-0 opacity-100" : "translate-y-4 opacity-0"
                )}
                style={{ transitionDelay: `${index * 100}ms` }}
              >
                <a
                  href={item.href}
                  onClick={() => setIsMobileMenuOpen(false)}
                  className="block font-display-sans text-2xl font-medium tracking-[0.35px] text-[#f0f0f0]"
                >
                  {item.label}
                </a>
              </li>
            ))}
            <li
              className={cn(
                "mt-8 flex flex-col gap-4 transform transition-all duration-500 delay-[500ms]",
                isMobileMenuOpen ? "translate-y-0 opacity-100" : "translate-y-4 opacity-0"
              )}
            >
              <a
                href="/resume.pdf"
                className="inline-flex items-center justify-center px-6 py-3 text-[16px] font-sans font-medium text-[#f0f0f0] border border-frost rounded-full hover-glass transition-colors"
                onClick={() => setIsMobileMenuOpen(false)}
              >
                Resume
              </a>
              <a
                href="#contact"
                className="inline-flex items-center justify-center px-6 py-3 text-[16px] font-sans font-medium text-[#000000] bg-[#ffffff] rounded-full"
                onClick={() => setIsMobileMenuOpen(false)}
              >
                Contact
              </a>
            </li>
          </ul>
        </div>,
        document.body
      )}
    </header>
  )
}
